import java.io.File;
import java.io.FileWriter;
import java.io.IOException;

import org.owasp.encoder.Encode;

public class XSSSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";
        String encodedUserInput = Encode.forHtml(userInput);

        try (FileWriter fileWriter = new FileWriter(new File("output.html"))) {
            fileWriter.write("<html>");
            fileWriter.write("<head><title>XSS Secure Page</title></head>");
            fileWriter.write("<body>");
            fileWriter.write("<h1>User Input: " + encodedUserInput + "</h1>");
            fileWriter.write("</body>");
            fileWriter.write("</html>");
        } catch (IOException e) {
            System.out.println("Error writing to file: " + e.getMessage());
        }
    }
}

